var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"더 이상 침식체와 싸우기 싫었어요. 무서운 주사도, 무기도, 다 싫었어요.","JPN":"もう侵食体と戦うのはイヤだったんです。怖い注射も、武器も、全部イヤだった。","ENG":"I don't want to fight C.O.s anymore. I hate it all, the scary needles and the weapons.","TWN":"我不想再和侵蝕體戰鬥了，我討厭可怕的注射器，我討厭武器，什麼都討厭。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"우린 친구들을 지키고 싶었어요. 모두 함께 행복하게 지내고 싶었어요.","JPN":"私たちはお友だちを守りたかった。みんな一緒に幸せに暮らしたかった。","ENG":"We just wanted to protect our friends. We wanted to all live happily.","TWN":"我們只是想保護朋友們，只是希望大家能一起幸福地生活。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"사랑하는 언니는 저를 지키기 위해 박사님에게 말대꾸를 했어요.","JPN":"大好きな姉さんは、私を守るために博士に口答えをしたんです。","ENG":"My beloved sister talked back to the doctor trying to protect me.","TWN":"親愛的姊姊為了保護我，頂撞了博士。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그런데… 주변의 군인 아저씨들이 무섭게 노려봤어요.","JPN":"それなのに……周りの軍人さんたちがすごく怖い目で睨んできたんです。","ENG":"But then... the soldiers around us started to glare at us scarily.","TWN":"但是……周圍的士兵叔叔們都兇狠地瞪著我們。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"드레카는 너무 무서워서… 언니를 위해 군인 아저씨들을 때렸어요.","JPN":"ドレカは怖すぎて……姉さんのために軍人さんを殴りました。","ENG":"Dreka was so scared... that I started hitting the soldier for Eva.","TWN":"德蕾卡太害怕了……為了姊姊，攻擊了士兵叔叔們。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"군인 아저씨들이 저흴 마구 쐈어요. 저항할 수가 없었어요.","JPN":"軍人さんは私たちに銃を撃ってきたんです。抵抗できなかった。","ENG":"Then, the soldiers started shooting at us. We couldn't resist.","TWN":"士兵叔叔們瘋狂朝我們掃射，我們根本無力反抗。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"언니는 분쇄기에 넣어졌고, 전 아주 험한 일을 당하게 되었어요.","JPN":"姉さんは粉砕機に放り込まれ、私はとてもひどいことをされました。","ENG":"Eva was put into a shredder, and I was put through horrible stuff.","TWN":"姊姊被扔進了粉碎機，而我經歷了非常可怕的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"무슨 일이었는지는… 기억하고 싶지 않아요.","JPN":"どんなことだったかは……思い出したくないです。","ENG":"The stuff they did to me... I don't want to remember.","TWN":"那是什麼事……我不想記得。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"책에선, 악당에 맞선 영웅은 항상 이겼다고 적혀 있었어요.","JPN":"本には、悪党に立ち向かった英雄はいつも勝利を収めたと書いてありました。","ENG":"In books, it's written that heroes always win against the villains.","TWN":"書上說，英雄總是能打敗壞蛋。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"그런데… 우린 항상 괴로웠어요.","JPN":"でも……私たちはいつも苦しかった。","ENG":"But... we were always in pain.","TWN":"但是……我們都很痛苦。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"매일 매일… 많이 울었어요.","JPN":"毎日毎日……すごく泣きました。","ENG":"Every day... we cried.","TWN":"每天每天……都在哭泣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"몰라볼 정도로 강해졌네.","JPN":"見違えるほどに強くなったね。","ENG":"You've become stronger than before.","TWN":"姊姊變得強大到認不出來了。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그런데 호흡도 거칠어지고, 아파하기까지 하던데.","JPN":"でも呼吸も荒いし、苦痛も感じてそうだけど。","ENG":"But your breathing is harsh, and you seem to feel pain.","TWN":"但是呼吸也變得很喘，是很痛苦嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"혹시… 지금 인간 흉내라도 내는 거야?","JPN":"もしかして……今、人間の真似でもしてる？","ENG":"Are you... mimicking a human?","TWN":"難道……現在是開始模仿人類了嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"……역겨워라.","JPN":"……不愉快だなあ。","ENG":"...Disgusting.","TWN":"……真噁心。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"부러우면 너도 따라 해보지 그래?","JPN":"うらやましいなら、あなたも真似してみたら？","ENG":"Why don't you copy me if you're that jealous?","TWN":"羡慕的話，你也來試試啊？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"조금은, 인간처럼 대해줄 수도 있는데?","JPN":"少しは人間のように接してあげられなくもないけど。","ENG":"Then, I might be able to treat you more like a human being.","TWN":"或許，我會稍微把你當成人類對待？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ff3636>키킥…!</color>","JPN":"<color=#ff3636>ククッ……！</color>","ENG":"<color=#ff3636>Keke...!</color>","TWN":"<color=#ff3636>嘻嘻……！</color>"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ff3636>훗, 아하하핫!!</color>","JPN":"<color=#ff3636>ふっ、あはははっ！！</color>","ENG":"<color=#ff3636>Pfft... Ah ha ha hah!!</color>","TWN":"<color=#ff3636>呵，哈哈哈！！</color>"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"크윽…!","JPN":"くうっ……！","ENG":"Kgh...!","TWN":"呃……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"하아… 하아…!","JPN":"はあ……はあ……！","ENG":"*Huff* *Huff*","TWN":"哈啊……哈啊……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"왜 그렇게까지 저항하는 거야?","JPN":"どうしてそこまで抵抗するの？","ENG":"Why are you resisting so much?","TWN":"為什麼要這麼抵抗？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"언니는 날 이길 수 없어.","JPN":"マブカさんは勝てないよ。","ENG":"You can't win against me.","TWN":"姊姊你贏不了我的。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"계속해서 나한테 달려들어도 더 아파질 텐데…","JPN":"私に挑み続けても、苦痛が増すだけなのに……","ENG":"It'll only hurt more if you continue trying to attack me.","TWN":"繼續攻擊也只會得到更多痛苦……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그래서… 내가 더 이상 아프지 않게 도와주려 했단 말이야.","JPN":"だから……私がもう苦しまないように手伝ってあげようとしてたんだよ。","ENG":"So... I was going to help you not be in pain anymore.","TWN":"所以……我是為了讓你不再痛苦才幫忙的，姊姊。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"난 정말 언니를 위해서 였는데…!","JPN":"私は本当にマブカさんのことを思っていたのに……！","ENG":"It was really all for you...!","TWN":"我真的是為了姊姊……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"크윽…!","JPN":"くうっ……！","ENG":"Kgh...!","TWN":"呃……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"언니라면 잘 알잖아.","JPN":"マブカさんならよくわかってるでしょう？","ENG":"You know just as well as I do, Mavka.","TWN":"姊姊你應該很清楚。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"북방군에 저항하는건 아무 의미 없다는걸.","JPN":"北方軍に抵抗したところで、何の意味もないってこと。","ENG":"Resisting against the Northern Army is useless.","TWN":"對抗北方軍沒有任何意義。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"이제라도 우리 곁으로 돌아와 언니.","JPN":"今からでも私たちのそばに戻ってきて、マブカさん。","ENG":"So come back to our side, Mavka.","TWN":"現在回到我們身邊吧，姊姊。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"정말 즐거운 게 뭔지, 하나부터 열까지 다 알려줄 테니까.","JPN":"本当に楽しいことが何なのか、一から十まで全部教えてあげるから。","ENG":"I'll teach you everything about what fun really is.","TWN":"我會從頭到尾告訴你什麼是真正的快樂。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"네 변태 같은 취미에 어울려 줄 생각 없어.","JPN":"あなたの変態じみた趣味に付き合うつもりはない。","ENG":"I'm not interested in your perverted hobbies.","TWN":"我可不打算配合你那變態的興趣。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"너희들은 내 친구를 죽였고, 지금도 마을을 파괴하고 있지.","JPN":"あなたたちは私の友だちを殺したうえに村まで破壊してる。","ENG":"You killed my friends, and are still trying to destroy this village.","TWN":"你們殺了我的朋友，還試圖毀了我們的村子。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"그럼에도 가만히 있으라고?","JPN":"なのに、大人しくしろって？","ENG":"And you want me to just stand back and watch?","TWN":"即便如此，你還想讓我袖手旁觀？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"그럼 나도 하나만 묻자.","JPN":"じゃあ、私からも聞くよ。","ENG":"Let me ask you something.","TWN":"那我也問你一個問題。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"왜 그 놈들에게 저항하지 않지?","JPN":"どうしてあいつらに抵抗しない？","ENG":"Why didn't you resist against them?","TWN":"為什麼不反抗那些傢伙？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"이게 정말 너희들이 바랐던 모습이란 말이야?","JPN":"これが本当にあなたたちが望んでいた姿なの？","ENG":"Is this really what you wanted to become?","TWN":"這真的是你們所期望的樣子嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"너도 고통스러웠던 일이 많았을 거 아냐!","JPN":"あなたも苦しいことがたくさんあったはずでしょう！","ENG":"Didn't you also experience a lot of pain from them?!","TWN":"你也經歷了很多痛苦的事情吧！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"솔직히… 네가 불쌍하다고 느낄 정도야.","JPN":"正直……あなたが可哀想って思うくらいだよ。","ENG":"Honestly... I feel sorry for you.","TWN":"老實說……我甚至有些可憐你。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"저항하지 않는다고…?","JPN":"抵抗しない……？","ENG":"I didn't resist...?","TWN":"你說我……不反抗……？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"내가… 불쌍해?","JPN":"私が……可哀想？","ENG":"You feel... sorry for me?","TWN":"你覺得……我……可憐嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"정말 오랜만에 느껴봐. 죽여버리고 싶을 정도로 화나는 기분은.","JPN":"本当に久しぶりだよ。殺したいくらいイライラする気分は。","ENG":"It's been a long time since I felt angry enough to kill someone.","TWN":"好久沒有這種感覺了。氣得想殺人的感覺。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};